module div_16bit(
    input [15:0] A, 
    input [7:0] B,
    output reg [15:0] result, 
    output reg [15:0] odd
);
    reg [15:0] a_reg, b_reg;
    integer i;

    always @* begin
        a_reg = A;
        b_reg = B;

        for(i = 15; i >= 8; i = i - 1) begin
            if(a_reg[i:i-7] > b_reg) begin
                result[i-8] = 1;
                a_reg[i:i-7] = a_reg[i:i-7] - b_reg;
            end
            else begin
                result[i-8] = 0;
            end

            if(a_reg[i-8] != 0) begin
                odd = {a_reg[i-8], odd};
            end
        end

        odd = {a_reg[7:0], odd};
    end

endmodule
